  1→import { useInfiniteQuery, useQuery } from '@tanstack/react-query';
  2→import '../ProfilePage/myprofile.css';
  3→import './visitProfile.css';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { getFollowsData, getUserData, getUserJournals, getUserByUsername } from '../../../API/Api';
  6→import { Fragment, useEffect, useRef } from 'react';
  7→import { Outlet, useLocation, useNavigate, useParams } from 'react-router-dom';
  8→import Sidebar from '../SideBar/Sidebar';
  9→import { MoonLoader } from 'react-spinners';
 10→import { useFollowMutation } from '../../utils/useMutation';
 11→import debounce from '../../../helpers/debounce';
 12→import VerifiedBadge from '../Badge/VerifiedBadge';
 13→import formatCounts from '../../../helpers/fomatCounts';
 14→import MobileNavlink from '../mobileNavLink/MobileNavLink';
 15→import MobileSidebarLink from '../MobileSidebarLink/MobileSidebarLink';
 16→import { useState } from 'react';
 17→import WriteJournalButton from '../WriteJournalButton/WriteJournalButton';
 18→import Editor from '../HomePage/Editor/Editor';
 19→import Loader from '../loadingComponent/BgLoader';
 20→import useProfileSeo from '../../seo/useProfileSeo';
 21→import { createProfileSidebarLinks } from '../ProfilePage/constants/profileSidebarLinks';
 22→import ShareMenu from '../ShareMenu/ShareMenu';
 23→import { getProfileShareUrl } from '../../utils/getShareUrl';
 24→import StreakBadge from '../Streak/StreakBadge';
 25→import useStreakData from '../Streak/useStreakData';
 26→
 27→const Visitprofile = () =>{
 28→    const location = useLocation();
 29→    const stateData = location.state;
 30→    const { username: urlUsername } = useParams();
 31→    const queryUserId = new URLSearchParams(location.search).get('userId');
 32→    const isUsernameRoute = !!urlUsername;
 33→
 34→    // Fetch user by username if on /@username route
 35→    const { data: usernameData, isLoading: isLoadingByUsername } = useQuery({
 36→        queryKey: ['userByUsername', urlUsername],
 37→        queryFn: () => getUserByUsername(urlUsername),
 38→        enabled: isUsernameRoute,
 39→        staleTime: 1000 * 60 * 5,
 40→        refetchOnWindowFocus: false,
 41→    });
 42→
 43→    // Resolve visitedUserId from either username lookup, state, or query param
 44→    const visitedUserId = isUsernameRoute
 45→        ? usernameData?.userData?.[0]?.id
 46→        : (stateData?.userId || queryUserId);
 47→
 48→    const resolvedUsername = isUsernameRoute
 49→        ? urlUsername
 50→        : usernameData?.userData?.[0]?.username;
 51→
 52→    const {session, user, notifCount, loading} = useAuth();
 53→
 54→    const [showSidebar, setShowSidebar]= useState(false)
 55→    const [opendRichTextEditor, setOpenRichTextEditor] = useState(false);
 56→    const [showShareMenu, setShowShareMenu] = useState(false);
 57→
 58→    const { data: visitedStreakData } = useStreakData(visitedUserId);
 59→    const buttonRef = useRef();
 60→
 61→    const navigate = useNavigate();
 62→    const visitedProfileNavState = { userId: visitedUserId };
 63→    const visibleProfileSections = [{id: 'stats'}, {id: 'bio'}, {id: 'joined_date'}];
 64→
 65→    // Use @username paths when available, fall back to legacy /visitProfile paths
 66→    const profileUsername = resolvedUsername || usernameData?.userData?.[0]?.username;
 67→    const useNewUrls = !!profileUsername;
 68→    const tablists = useNewUrls
 69→        ? [
 70→            {label: 'Writings', path: `/u/${profileUsername}`, action: () => navigate(`/u/${profileUsername}`, {state: visitedProfileNavState})},
 71→            {label: 'Media', path: `/u/${profileUsername}/media`, action: () => navigate(`/u/${profileUsername}/media`, {state: visitedProfileNavState})},
 72→            {label: 'Opinions', path: `/u/${profileUsername}/opinions`, action: () => navigate(`/u/${profileUsername}/opinions`, {state: visitedProfileNavState})},
 73→            {label: 'Stories', path: `/u/${profileUsername}/stories`, action: () => navigate(`/u/${profileUsername}/stories`, {state: visitedProfileNavState})}
 74→        ]
 75→        : [
 76→            {label: 'Writings', path: '/visitProfile', action: () => navigate(`/visitProfile?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 77→            {label: 'Media', path: '/visitProfile/media', action: () => navigate(`/visitProfile/media?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 78→            {label: 'Opinions', path:'/visitProfile/visitedOpinions', action: () => navigate(`/visitProfile/visitedOpinions?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})},
 79→            {label: 'Stories', path:'/visitProfile/stories', action: () => navigate(`/visitProfile/stories?userId=${visitedUserId || ''}`, {state: visitedProfileNavState})}
 80→        ]
 81→
 82→     const navigatePath = (path) => {
 83→        return navigate(path)
 84→    }
 85→
 86→    const handleMouseMove = (isFollowing) =>{
 87→        if(buttonRef.current){
 88→            if(isFollowing){
 89→                buttonRef.current.innerText = 'Unfollow'
 90→            } else {
 91→                return
 92→            }
 93→        }
 94→    }
 95→
 96→    //open rich text editor
 97→    const handleClickRichtextEditor = () =>{
 98→        setOpenRichTextEditor(true);
 99→    }
100→    //close rich text editor
101→    const handleCloseRichtextEditor = () =>{
102→        setOpenRichTextEditor(false);
103→    }
104→
105→    // open sidebar through boolean function
106→    const openSidebar = () =>{
107→        setShowSidebar(true)
108→    }
109→
110→    // close sidebar through boolean function
111→    const closeSidebar = () =>{
112→        setShowSidebar(false)
113→    }
114→
115→    const handleMouseLeave = (isFollowing) =>{
116→        if(buttonRef.current){
117→            if(isFollowing){
118→                buttonRef.current.innerText = 'Following'
119→            } else {
120→                return
121→            }
122→        }
123→    }
124→
125→    const mutationFollow = useFollowMutation(session, visitedUserId);
126→    const hadnleClickFollow = (e, followingId, followerId,) =>{
127→        mutationFollow.mutate({followingId, followerId})
128→    }
129→    const debounceClickFollow = debounce(hadnleClickFollow, 0)
130→
131→    const links = createProfileSidebarLinks({
132→        location,
133→        navigatePath,
134→        navigate,
135→        notifCount,
136→        setShowEditor: setOpenRichTextEditor,
137→    });
138→
139→    
140→    const {data, isLoading} = useQuery({
141→        queryKey: ['visitedProfile', visitedUserId],
142→        queryFn:({queryKey}) => getUserData(queryKey[1]),
143→        enabled: !!visitedUserId && !isUsernameRoute,
144→        refetchOnWindowFocus: false,
145→        staleTime: 1000 * 60 * 10
146→    })
147→
148→    // Use username-fetched data when on /@username route, otherwise use userId-fetched data
149→    const userData = isUsernameRoute
150→        ? usernameData?.userData?.[0]
151→        : data?.userData?.[0]
152→
153→    useProfileSeo(userData, profileUsername);
154→    const getProfileSectionSize = () => 'md';
155→
156→    const{data: followsData, isLoading: isLoadingFollowsData} = useQuery({
157→        queryKey: ['followsData', user?.userData?.[0].id, visitedUserId],
158→        queryFn: ({queryKey}) => getFollowsData(session?.access_token, queryKey[2]),
159→        staleTime: 1000 * 60 * 60,
160→        gcTime: 1000 * 60 * 60,
161→        enabled: !!user?.userData?.[0].id && !!visitedUserId,
162→        refetchOnWindowFocus: false
163→    })
164→
165→
166→    useEffect(() =>{
167→        // console.log(data)
168→    }, [data])
169→
170→    useEffect(() => {
171→        if(!session && !loading){
172→            return navigate('/login')
173→            //check if the user has user metadata on the users table database if not then show a UI that let them input there data and save to database
174→        }
175→    
176→    },[session, loading])
177→
178→    if(isLoading || isLoadingByUsername){
179→        return(
180→            <Loader/>
181→        )
182→    }
183→    return(
184→        <>{opendRichTextEditor &&(
185→            <Editor onClose={handleCloseRichtextEditor}/>
186→        )}
187→        
188→        <div className='profile-parent-container'>
189→            {userData?.background && (
190→                <div className="blurred-img-bg" style={userData?.background}/>
191→            )}
192→
193→            <div className="side-bar-holder-container">
194→                <Sidebar links={links}/> {/*passing the setShowEditor to this component to be used as a state setter inside this component*/}
195→            </div>
196→
197→            <div style={{color: userData?.profile_font_color}} className="profile-center-bar-container">
198→                {userData && (
199→
200→                    <div style={userData?.background} className='visit-profile-hero-section'>
201→
202→                        <div className='visited-profile-top-row'>
203→                            <div className={`profile-avatar-ring ${userData?.badge === 'legend' ? 'badge-ring-legend' : userData?.badge === 'og' ? 'badge-ring-og' : ''}`}>
204→                                <img className='visited-profile-image' src={userData?.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
205→                            </div>
206→                        </div>
207→
208→                        <div className='visited-profile-name-container'>
209→                            <div className='visited-profile-name-row'>
210→                                <p className='visited-profile-name'>{userData?.name}</p>
211→                                <VerifiedBadge badge={userData?.badge} size={22} />
