 22→function RelatedPostCard({ post, index }) {
 23→    const navigate = useNavigate();
 24→
 25→    const handleClick = () => {
 26→        navigate(`/home/post/${post.id}`);
 27→    };
 28→
 29→    const title = post.title || 'Untitled';
 30→    const excerpt = extractExcerpt(post.preview_text);
 31→
 32→    // Map similarity to accent opacity (higher = brighter accent line)
 33→    const accentOpacity = Math.min(1, Math.max(0.3, (post.semantic_similarity - 0.25) / 0.5));
 34→
 35→    return (
 36→        <motion.div
 37→            className="rp-card"
 38→            onClick={handleClick}
 39→            initial={{ opacity: 0, y: 12 }}
 40→            animate={{ opacity: 1, y: 0 }}
 41→            transition={{
 42→                duration: 0.35,
 43→                delay: index * 0.06,
 44→                ease: [0.25, 0.46, 0.45, 0.94],
 45→            }}
 46→        >
 47→            <div
 48→                className="rp-card-accent"
 49→                style={{ opacity: accentOpacity }}
 50→            />
 51→            <div className="rp-card-content">
 52→                <h4 className="rp-card-title">{title}</h4>
 53→                {excerpt && <p className="rp-card-excerpt">{excerpt}</p>}
 54→                <div className="rp-card-meta">
 55→                    <div className="rp-card-author">
 56→                        <div className={`rp-card-avatar-container ${post.user_badge === 'legend' ? 'rp-avatar-ring-legend' : post.user_badge === 'og' ? 'rp-avatar-ring-og' : ''}`}>
 57→                            {post.user_image_url ? (
 58→                                <img
 59→                                    src={post.user_image_url}
 60→                                    alt=""
 61→                                    className="rp-card-avatar"
 62→                                />
 63→                            ) : (
 64→                                <div className="rp-card-avatar rp-card-avatar-placeholder" />
 65→                            )}
 66→                        </div>
 67→                        <span className="rp-card-name">
 68→                            {post.user_name || 'Anonymous'}
 69→                        </span>
 70→                        {post.user_badge && (
 71→                            <VerifiedBadge badge={post.user_badge} size={12} />
 72→                        )}
 73→                    </div>
 74→                    <span className="rp-card-date">
 75→                        {formatPostDate(post.created_at)}
 76→                    </span>
 77→                </div>
 78→            </div>
 79→        </motion.div>
 80→    );
 81→}
